// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAXN 500
#define MAXM 1000000
int N, M;
int s[MAXM];
int dp[MAXN][MAXN];
int distance(int i, int j) {
    if (i == j) return 0;
    if (i < j) return j - i;
    return i - j;
}
int min(int a, int b) {
    return a < b ? a : b;
}
int main() {
    scanf("%d %d", &N, &M);
    for (int i = 0; i < M; i++) {
        scanf("%d", &s[i]);
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = INT_MAX;
        }
    }
    for (int i = 0; i < N; i++) {
        dp[i][i] = 0;
    }
    for (int len = 2; len <= N; len++) {
        for (int i = 0; i <= N - len; i++) {
            int j = i + len - 1;
            for (int k = i; k <= j; k++) {
                int cost = dp[i][k] + dp[k+1][j] + distance(s[0], k) + distance(k, s[1]);
                dp[i][j] = min(dp[i][j], cost);
            }
        }
    }
    printf("%d\n", dp[0][N-1]);
    return 0;
}

