import java.util.Scanner;
public class Main {
    static final int MAXN = 500;
    static final int MAXM = 1000000;
    static int N, M;
    static int[] s = new int[MAXM];
    static int[][] dp = new int[MAXN][MAXN];
    static int distance(int i, int j) {
        if (i == j) return 0;
        if (i < j) return j - i;
        return i - j;
    }
    static int min(int a, int b) {
        return a < b ? a : b;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        N = scanner.nextInt();
        M = scanner.nextInt();
        for (int i = 0; i < M; i++) {
            s[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }
        for (int i = 0; i < N; i++) {
            dp[i][i] = 0;
        }
        for (int len = 2; len <= N; len++) {
            for (int i = 0; i <= N - len; i++) {
                int j = i + len - 1;
                for (int k = i; k <= j; k++) {
                    int cost = dp[i][k] + dp[k+1][j] + distance(s[0], k) + distance(k, s[1]);
                    dp[i][j] = min(dp[i][j], cost);
                }
            }
        }
        System.out.println(dp[0][N-1]);
    }
}

